external_knowledge:
big cities: cities with populations over 100,000; 
modified: an update has been recorded in the location's history;
details: includes location ID, address, city, state, zip, and city population.

sql:
SELECT * 
FROM locations 
WHERE location_id NOT IN (SELECT location_id FROM location_tags);

SELECT COUNT(DISTINCT location_id)
FROM location_analytics
WHERE metric_name = 'proximity';

SELECT AVG(metric_value) AS average_distance
FROM location_analytics
WHERE metric_name = 'distance';
